        adminViewModel.revenue.observe(this, Observer { revenue ->
            binding.revenueTextView.text = "₹${revenue}"
        })

        adminViewModel.isLoading.observe(this, Observer { isLoading ->
            // Show/hide loading
        })

        adminViewModel.error.observe(this, Observer { error ->
            error?.let {
                Toast.makeText(this, it, Toast.LENGTH_SHORT).show()
            }
        })
    }

    private fun loadBusinessState() {
        val uid = FirebaseAuth.getInstance().currentUser?.uid ?: return
        val db = com.google.firebase.firestore.FirebaseFirestore.getInstance()
        db.collection("businesses")
            .whereEqualTo("ownerId", uid)
            .limit(1)
            .get()
            .addOnSuccessListener { result ->
                val doc = result.documents.firstOrNull()
                adminBusinessId = doc?.id
                adminBusinessApproved = doc?.getBoolean("approved") == true

                if (adminBusinessId.isNullOrBlank()) {
                    binding.addServiceButton.text = "Create Business"
                    binding.businessStatusTextView.text = "No business found. Create one to continue."
                    binding.businessStatusTextView.setTextColor(Color.RED)
                    Toast.makeText(this, "No business found. Create one to continue.", Toast.LENGTH_SHORT).show()
                    return@addOnSuccessListener
                }

                android.util.Log.d("ADMIN_DEBUG", "Business ID: $adminBusinessId, Approved: $adminBusinessApproved")

                if (!adminBusinessApproved) {
                    Toast.makeText(this, "Business waiting for approval", Toast.LENGTH_SHORT).show()
                    binding.businessStatusTextView.text = "Pending approval. Please wait..."
                    binding.businessStatusTextView.setTextColor(Color.RED)
                } else {
                    binding.businessStatusTextView.text = "Business Active"
                    binding.businessStatusTextView.setTextColor(Color.parseColor("#16A34A"))
                    android.util.Log.d("ADMIN_DEBUG", "Loading dashboard data for businessId: $adminBusinessId")
                    adminViewModel.loadDashboardData(uid, adminBusinessId!!)
                }
            }
    }

    private fun createBusinessForAdmin() {
        val uid = FirebaseAuth.getInstance().currentUser?.uid ?: return
        val db = com.google.firebase.firestore.FirebaseFirestore.getInstance()
        val business = hashMapOf(
            "name" to "Business $uid",
            "ownerId" to uid,
            "approved" to false,
            "createdAt" to System.currentTimeMillis()
        )
        db.collection("businesses")
            .add(business)
            .addOnSuccessListener {
                Toast.makeText(this, "Business created. Waiting for approval.", Toast.LENGTH_SHORT).show()
                loadBusinessState()
            }
            .addOnFailureListener { e ->
                Toast.makeText(this, "Error: ${e.message}", Toast.LENGTH_SHORT).show()
            }
    }
}

package com.sudhir.localeasy1.ui.adapters

import android.view.LayoutInflater
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import com.sudhir.localeasy1.data.Booking
import com.sudhir.localeasy1.databinding.ItemServiceBookingBinding
import java.text.SimpleDateFormat
import java.util.*

class ServiceBookingItemAdapter(
    private var bookings: List<Booking>,
    private val onCallClick: (Booking) -> Unit
) : RecyclerView.Adapter<ServiceBookingItemAdapter.ViewHolder>() {

    inner class ViewHolder(private val binding: ItemServiceBookingBinding) :
        RecyclerView.ViewHolder(binding.root) {

        fun bind(booking: Booking) {
            // Set name
            binding.userName.text = booking.userName

            // Set phone
            binding.userPhone.text = " ${booking.phone}"

            // Format and set time
            val formattedTime = formatTime(booking.time)
            binding.bookingTime.text = " $formattedTime"

            // Set booking status with color
            binding.bookingStatus.text = booking.status.uppercase()
            binding.bookingStatus.setBackgroundColor(
                when (booking.status) {
                    "confirmed" -> android.graphics.Color.parseColor("#22C55E")
                    "completed" -> android.graphics.Color.parseColor("#3B82F6")
                    "cancelled" -> android.graphics.Color.parseColor("#EF4444")
                    else -> android.graphics.Color.parseColor("#F59E0B") // pending
                }
            )

            // Call button
            binding.callBtn.setOnClickListener {
                onCallClick(booking)
            }
        }

        private fun formatTime(timeMillis: Long): String {
            return try {
                val calendar = Calendar.getInstance().apply {
                    this.timeInMillis = timeMillis
                }
                SimpleDateFormat("dd MMM, yyyy hh:mm a", Locale.getDefault()).format(calendar.time)
            } catch (e: Exception) {
                "Time not available"
            }
        }
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ViewHolder {
        val binding = ItemServiceBookingBinding.inflate(
            LayoutInflater.from(parent.context),
            parent,
            false
        )
        return ViewHolder(binding)
    }

    override fun onBindViewHolder(holder: ViewHolder, position: Int) {
        holder.bind(bookings[position])
    }

    override fun getItemCount(): Int = bookings.size

    fun updateBookings(newBookings: List<Booking>) {
        bookings = newBookings
        notifyDataSetChanged()
    }
}

package com.sudhir.localeasy1.ui.adapters

import android.view.LayoutInflater
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import com.sudhir.localeasy1.data.Booking
import com.sudhir.localeasy1.databinding.ItemServiceBookingBinding
import java.text.SimpleDateFormat
import java.util.*

class ServiceBookingItemAdapter(
    private var bookings: List<Booking>,
    private val onCallClick: (Booking) -> Unit
) : RecyclerView.Adapter<ServiceBookingItemAdapter.ViewHolder>() {

    inner class ViewHolder(private val binding: ItemServiceBookingBinding) :
        RecyclerView.ViewHolder(binding.root) {

        fun bind(booking: Booking) {
            // Set service name
            binding.serviceName.text = booking.serviceName

            // Set user name (clean, no prefixes)
            binding.userName.text = booking.userName

            // Set phone (clean, no prefixes)
            binding.userPhone.text = booking.phone

            // Format and set date and time separately
            val (dateStr, timeStr) = formatDateTime(booking.time)
            binding.bookingDate.text = dateStr
            binding.bookingTime.text = timeStr

            // Set booking status with color
            binding.bookingStatus.text = booking.status.uppercase()
            binding.bookingStatus.setBackgroundColor(
                when (booking.status) {
                    "confirmed" -> android.graphics.Color.parseColor("#22C55E")
                    "completed" -> android.graphics.Color.parseColor("#3B82F6")
                    "cancelled" -> android.graphics.Color.parseColor("#EF4444")
                    else -> android.graphics.Color.parseColor("#F59E0B") // pending
                }
            )

            // Call button
            binding.callBtn.setOnClickListener {
                onCallClick(booking)
            }
        }

        private fun formatDateTime(timeMillis: Long): Pair<String, String> {
            return try {
                val calendar = Calendar.getInstance().apply {
                    this.timeInMillis = timeMillis
                }

                val dateFormat = SimpleDateFormat("dd MMM yyyy", Locale.getDefault())
                val timeFormat = SimpleDateFormat("hh:mm a", Locale.getDefault())

                val dateStr = dateFormat.format(calendar.time)
                val timeStr = timeFormat.format(calendar.time)

                Pair(dateStr, timeStr)
            } catch (e: Exception) {
                Pair("Date not available", "Time not available")
            }
        }
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ViewHolder {
        val binding = ItemServiceBookingBinding.inflate(
            LayoutInflater.from(parent.context),
            parent,
            false
        )
        return ViewHolder(binding)
    }

    override fun onBindViewHolder(holder: ViewHolder, position: Int) {
        holder.bind(bookings[position])
    }

    override fun getItemCount(): Int = bookings.size

    fun updateBookings(newBookings: List<Booking>) {
        bookings = newBookings
        notifyDataSetChanged()
    }
}

package com.sudhir.localeasy1.ui.viewmodel

import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.sudhir.localeasy1.data.Booking
import com.sudhir.localeasy1.data.Service
import com.sudhir.localeasy1.repository.BookingRepository
import com.sudhir.localeasy1.repository.ServiceRepository
import kotlinx.coroutines.launch

class AdminViewModel : ViewModel() {
    private val bookingRepository = BookingRepository()
    private val serviceRepository = ServiceRepository()

    private val _bookings = MutableLiveData<List<Booking>>()
    val bookings: LiveData<List<Booking>> = _bookings

    private val _services = MutableLiveData<List<Service>>()
    val services: LiveData<List<Service>> = _services

    private val _isLoading = MutableLiveData(false)
    val isLoading: LiveData<Boolean> = _isLoading

    private val _error = MutableLiveData<String?>()
    val error: LiveData<String?> = _error

    private val _bookingsToday = MutableLiveData(0)
    val bookingsToday: LiveData<Int> = _bookingsToday

    private val _revenue = MutableLiveData(0.0)
    val revenue: LiveData<Double> = _revenue

    fun loadDashboardData(businessId: String) {
        loadBookings(businessId)
        loadServices(businessId)
    }

    private fun loadBookings(businessId: String) {
        viewModelScope.launch {
            _isLoading.value = true
            _error.value = null
            try {
                val bookingList = bookingRepository.getBusinessBookings(businessId)
                    .sortedByDescending { it.time }
                _bookings.value = bookingList
                calculateStats(bookingList, _services.value ?: emptyList())
            } catch (e: Exception) {
                _error.value = e.message ?: "Failed to load bookings"
            } finally {
                _isLoading.value = false
            }
        }
    }

    private fun loadServices(businessId: String) {
        viewModelScope.launch {
            try {
                // In real app, filter by businessId
                val serviceList = serviceRepository.getAllServices()
                    .filter { it.businessId == businessId }
                _services.value = serviceList
                calculateStats(_bookings.value ?: emptyList(), serviceList)
            } catch (e: Exception) {
                _error.value = e.message ?: "Failed to load services"
            }
        }
    }

    private fun calculateStats(bookings: List<Booking>, services: List<Service>) {
        val today = System.currentTimeMillis()
        val calendar = java.util.Calendar.getInstance()
        calendar.timeInMillis = today
        calendar.set(java.util.Calendar.HOUR_OF_DAY, 0)
        calendar.set(java.util.Calendar.MINUTE, 0)
        calendar.set(java.util.Calendar.SECOND, 0)
        calendar.set(java.util.Calendar.MILLISECOND, 0)
        val startOfDay = calendar.timeInMillis
        val endOfDay = startOfDay + (24 * 60 * 60 * 1000)

        // Count all bookings created today OR scheduled for today
        val todayBookings = bookings.filter { 
            (it.createdAt in startOfDay until endOfDay) || (it.time in startOfDay until endOfDay)
        }
        _bookingsToday.value = todayBookings.size

        // Calculate revenue only for confirmed or completed bookings
        var totalRevenue = 0.0
        bookings.filter { it.status == "confirmed" || it.status == "completed" }
            .forEach { booking ->
                // Look for price in the booking first, then service
                val price = try {
                    // Try to find matching service to get price
                    val service = services.find { it.id == booking.serviceId }
                    service?.price?.toDouble() ?: 0.0
                } catch (e: Exception) {
                    0.0
                }
                totalRevenue += price
            }

        android.util.Log.d("ADMIN_STATS", "Stats Summary: Total Bookings=${bookings.size}, Today Count=${todayBookings.size}, Confirmed Revenue=$totalRevenue")
        _revenue.value = totalRevenue
    }

    fun updateBookingStatus(bookingId: String, status: String, businessId: String) {
        viewModelScope.launch {
            _isLoading.value = true
            _error.value = null
            try {
                val result = bookingRepository.updateBookingStatus(bookingId, status)
                result.onSuccess {
                    loadBookings(businessId)
                }.onFailure { e ->
                    _error.value = e.message ?: "Failed to update booking"
                }
            } catch (e: Exception) {
                _error.value = e.message ?: "Failed to update booking"
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun addService(service: Service) {
        viewModelScope.launch {
            _isLoading.value = true
            _error.value = null
            try {
                val result = serviceRepository.addService(service)
                result.onSuccess {
                    // Reload services
                    val businessId = service.businessId
                    loadServices(businessId)
                }.onFailure { e ->
                    _error.value = e.message ?: "Failed to add service"
                }
            } catch (e: Exception) {
                _error.value = e.message ?: "Failed to add service"
            } finally {
                _isLoading.value = false
            }
        }
    }
}

package com.sudhir.localeasy1.ui.viewmodel

import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.sudhir.localeasy1.data.Booking
import com.sudhir.localeasy1.data.Service
import com.sudhir.localeasy1.repository.BookingRepository
import com.sudhir.localeasy1.repository.ServiceRepository
import kotlinx.coroutines.launch

class AdminViewModel : ViewModel() {
    private val bookingRepository = BookingRepository()
    private val serviceRepository = ServiceRepository()

    private var ownerId: String = ""

    private val _bookings = MutableLiveData<List<Booking>>()
    val bookings: LiveData<List<Booking>> = _bookings

    private val _services = MutableLiveData<List<Service>>()
    val services: LiveData<List<Service>> = _services

    private val _isLoading = MutableLiveData(false)
    val isLoading: LiveData<Boolean> = _isLoading

    private val _error = MutableLiveData<String?>()
    val error: LiveData<String?> = _error

    private val _bookingsToday = MutableLiveData(0)
    val bookingsToday: LiveData<Int> = _bookingsToday

    private val _revenue = MutableLiveData(0.0)
    val revenue: LiveData<Double> = _revenue

    fun loadDashboardData(ownerId: String, businessId: String) {
        this.ownerId = ownerId
        loadBookings(ownerId)
        loadServices(businessId)
    }

    private fun loadBookings(ownerId: String) {
        viewModelScope.launch {
            _isLoading.value = true
            _error.value = null
            try {
                val bookingList = bookingRepository.getBookingsForOwner(ownerId)
                    .sortedByDescending { it.time }

                // DEBUG LOGGING
                android.util.Log.d("ADMIN_DEBUG", "Querying bookings for ownerId: $ownerId")
                android.util.Log.d("ADMIN_DEBUG", "Found ${bookingList.size} bookings for ownerId: $ownerId")
                bookingList.forEach { booking ->
                    android.util.Log.d("ADMIN_DEBUG", "Loaded booking: service=${booking.serviceName}, businessId=${booking.businessId}, user=${booking.userName}")
                }

                _bookings.value = bookingList
                calculateStats(bookingList, _services.value ?: emptyList())
            } catch (e: Exception) {
                _error.value = e.message ?: "Failed to load bookings"
                android.util.Log.e("ADMIN_DEBUG", "Error loading bookings", e)
            } finally {
                _isLoading.value = false
            }
        }
    }

    private fun loadServices(businessId: String) {
        viewModelScope.launch {
            try {
                // Use the new method to get services specifically for this business
                val serviceList = serviceRepository.getServicesByBusinessId(businessId)
                _services.value = serviceList
                calculateStats(_bookings.value ?: emptyList(), serviceList)
            } catch (e: Exception) {
                _error.value = e.message ?: "Failed to load services"
            }
        }
    }

    private fun calculateStats(bookings: List<Booking>, services: List<Service>) {
        val today = System.currentTimeMillis()
        val calendar = java.util.Calendar.getInstance()
        calendar.timeInMillis = today
        calendar.set(java.util.Calendar.HOUR_OF_DAY, 0)
        calendar.set(java.util.Calendar.MINUTE, 0)
        calendar.set(java.util.Calendar.SECOND, 0)
        calendar.set(java.util.Calendar.MILLISECOND, 0)
        val startOfDay = calendar.timeInMillis
        val endOfDay = startOfDay + (24 * 60 * 60 * 1000)

        // Count all bookings created today OR scheduled for today
        val todayBookings = bookings.filter { 
            (it.createdAt in startOfDay until endOfDay) || (it.time in startOfDay until endOfDay)
        }
        _bookingsToday.value = todayBookings.size

        // Calculate revenue only for confirmed or completed bookings
        var totalRevenue = 0.0
        bookings.filter { it.status == "confirmed" || it.status == "completed" }
            .forEach { booking ->
                // Look for price in the booking first, then service
                val price = try {
                    // Try to find matching service to get price
                    val service = services.find { it.id == booking.serviceId }
                    service?.price?.toDouble() ?: 0.0
                } catch (e: Exception) {
                    0.0
                }
                totalRevenue += price
            }

        android.util.Log.d("ADMIN_STATS", "Stats Summary: Total Bookings=${bookings.size}, Today Count=${todayBookings.size}, Confirmed Revenue=$totalRevenue")
        _revenue.value = totalRevenue
    }

    fun updateBookingStatus(bookingId: String, status: String, businessId: String) {
        viewModelScope.launch {
            _isLoading.value = true
            _error.value = null
            try {
                val result = bookingRepository.updateBookingStatus(bookingId, status)
                result.onSuccess {
                    loadBookings(this@AdminViewModel.ownerId)
                }.onFailure { e ->
                    _error.value = e.message ?: "Failed to update booking"
                }
            } catch (e: Exception) {
                _error.value = e.message ?: "Failed to update booking"
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun addService(service: Service) {
        viewModelScope.launch {
            _isLoading.value = true
            _error.value = null
            try {
                val result = serviceRepository.addService(service)
                result.onSuccess {
                    // Reload services
                    val businessId = service.businessId
                    loadServices(businessId)
                }.onFailure { e ->
                    _error.value = e.message ?: "Failed to add service"
                }
            } catch (e: Exception) {
                _error.value = e.message ?: "Failed to add service"
            } finally {
                _isLoading.value = false
            }
        }
    }
}
